bd list --status=in_progress --json --limit=0 2>&1 | python3 -c "
import json, sys
data = json.load(sys.stdin)
polecats = [b for b in data if 'polecats/' in (b.get('assignee','') or '')]
if polecats:
    for p in polecats:
        print(f'{p[\"id\"]} assigned to {p.get(\"assignee\",\"\")}')
else:
    print('No in_progress beads assigned to polecats')
" 2>&1

